package main

import (
    "sync"
)

type Bank struct {
    accounts map[string]float64
    mutex    sync.RWMutex
}

func NewBank() *Bank {
    return &Bank{
        accounts: make(map[string]float64),
    }
}

func (b *Bank) GetBalance(account string) float64 {
    b.mutex.RLock()
    defer b.mutex.RUnlock()
    return b.accounts[account]
}

func (b *Bank) Deposit(account string, amount float64) error {
    b.mutex.Lock()
    defer b.mutex.Unlock()
    b.accounts[account] += amount
    return nil
}

func (b *Bank) Withdraw(account string, amount float64) error {
    b.mutex.Lock()
    defer b.mutex.Unlock()
    if b.accounts[account] < amount {
        return fmt.Errorf("insufficient funds")
    }
    b.accounts[account] -= amount
    return nil
}

func (b *Bank) Transfer(from, to string, amount float64) error {
    b.mutex.Lock()
    defer b.mutex.Unlock()
    
    if b.accounts[from] < amount {
        return fmt.Errorf("insufficient funds")
    }
    
    b.accounts[from] -= amount
    b.accounts[to] += amount
    return nil
}

func (b *Bank) ProcessTransaction(account string, operation func(float64) float64) float64 {
    b.mutex.Lock()
    defer b.mutex.Unlock()
    b.accounts[account] = operation(b.accounts[account])
    return b.accounts[account]
}